package com.nutrisense.entity;
import jakarta.persistence.*; import lombok.*; import java.math.*; import java.time.*;
@Getter @Setter @Builder @NoArgsConstructor @AllArgsConstructor @Entity @Table(name="diet_plans") public class DietPlan { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="user_id",nullable=false) private User user; @Column(name="plan_name",nullable=false,length=150) private String planName; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="goal_id",nullable=false) private GoalType goal; @Column(name="total_calories",precision=8,scale=2) private BigDecimal totalCalories; @Column(precision=8,scale=2) private BigDecimal budget; @Column(name="start_date") private LocalDate startDate; @Column(name="end_date") private LocalDate endDate; @Column(name="is_active") private Boolean active; @Column(name="created_at",insertable=false,updatable=false) private Instant createdAt; @Column(name="updated_at",insertable=false,updatable=false) private Instant updatedAt; }
